#include <iostream>
#include <vector>
using namespace std;

int maxLoot(vector<int>& money, int n) {
    // Handle base cases
    if(n == 0) return 0;
    if(n == 1) return money[0];
    if(n == 2) return max(money[0], money[1]);

    // dp[i] represents maximum money that can be looted from first i houses
    vector<int> dp(n);

    // Initialize first two states
    dp[0] = money[0];
    dp[1] = max(money[0], money[1]);

    // Fill dp array
    for(int i = 2; i < n; i++) {
        // At each house, thief has two choices:
        // 1. Skip current house and take previous best (dp[i-1])
        // 2. Take current house and add to best possible from i-2 houses (dp[i-2] + money[i])
        dp[i] = max(dp[i-1], dp[i-2] + money[i]);
    }

    return dp[n-1];
}

int main() {
    int n;
    cin >> n;

    vector<int> money(n);
    for(int i = 0; i < n; i++) {
        cin >> money[i];
    }

    cout << maxLoot(money, n) << endl;

    return 0;
}
